+    #[test]
+    fn hit_id_debug_clone_copy_hash() {
+        let id = HitId::new(99);
+        let dbg = format!("{:?}", id);
+        assert!(dbg.contains("99"), "Debug: {dbg}");
+        let copied: HitId = id; // Copy
+        assert_eq!(id, copied);
+        // Hash: insert into set
+        use std::collections::HashSet;
+        let mut set = HashSet::new();
+        set.insert(id);
+        set.insert(HitId::new(99));
